import{_ as o,o as e,c as n,a5 as a}from"./chunks/framework.gGRxziV4.js";const h=JSON.parse('{"title":"Agent 工程的未来不在模型，在人","description":"","frontmatter":{"title":"Agent 工程的未来不在模型，在人","date":"2026-03-30T00:00:00.000Z","tags":["Agent","观点","判断力","上下文工程","评估"],"status":"草稿","series":"Agent 工程实践系列（第 4 篇 / 收尾篇）"},"headers":[],"relativePath":"blog/2026-03-30-Agent工程的未来在人.md","filePath":"blog/2026-03-30-Agent工程的未来在人.md","lastUpdated":null}'),r={name:"blog/2026-03-30-Agent工程的未来在人.md"};function s(l,t,g,p,u,i){return e(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="agent-工程的未来不在模型-在人" tabindex="-1">Agent 工程的未来不在模型，在人 <a class="header-anchor" href="#agent-工程的未来不在模型-在人" aria-label="Permalink to &quot;Agent 工程的未来不在模型，在人&quot;">​</a></h1><p>过去 30 天，我让一个 Agent 系统自己跑。它写文章、做评估、建客户名单。它每天醒来就执行任务，从不抱怨，从不请假，产出量是我的五倍以上。</p><p>但它做不了最关键的事：决定该做什么。</p><p>不是&quot;不知道怎么做&quot;，而是&quot;不该做这件事&quot;——这个判断，它至今学不会。</p><p>这篇文章是 30 天实验的收尾。前三篇我们拆解了执行过剩的问题、搭了一套 Agent 系统、建了一套评估框架。今天我想聊一个更底层的问题：<strong>Agent 工程的真正瓶颈，到底在哪里？</strong></p><p>我的回答是：不在模型，在人。</p><hr><h2 id="观点-1-上下文工程-模型能力" tabindex="-1">观点 1：上下文工程 &gt; 模型能力 <a class="header-anchor" href="#观点-1-上下文工程-模型能力" aria-label="Permalink to &quot;观点 1：上下文工程 &gt; 模型能力&quot;">​</a></h2><p>先说一个反直觉的事实。</p><p>在 Hermes Engineering 教程中，我们花了 24 篇文章讨论上下文工程——如何给 Agent 提供正确的信息、如何设计信息流、如何管理状态。但只用了不到 3 篇讨论模型本身的选择。</p><p>这不是因为我们觉得模型不重要，而是因为在 2026 年，<strong>模型能力已经不再是差异化因素</strong>。</p><p>同一个 GPT-4 级别的模型，给它不同质量的上下文，表现差距可以达到 3-5 倍。这不是猜测——我们用 Atlas 系统做了大量对比实验。把启动序列从&quot;直接执行&quot;改成&quot;先读状态文件、再读记忆日记、再领任务&quot;，同样的模型，任务完成率从 60% 提升到 85%。</p><p>模型没变。变的是喂给它的上下文。</p><p>Hermes 教程里有一个核心概念叫<strong>上下文腐烂（Context Rot）</strong>：上下文越长，模型在长距离推理和精确回忆方面的能力就越差。Menlo 的数据显示，一个典型 Agent 任务平均需要 50 次工具调用，生产级 Agent 的对话轮次可能长达数百轮。每一步决策都要背负之前所有轮次的结果。</p><p>这意味着：<strong>你给 Agent 的信息越多，不一定越好。</strong> 你给的信息越对，才越好。</p><p>上下文工程正在成为新的&quot;编程&quot;——但不是写代码，是设计信息流。</p><p>传统程序员写的是逻辑：if this, then that。上下文工程师设计的是环境：在什么时间点，给 Agent 什么信息，用什么格式，排除什么噪音。前者是给机器下命令，后者是给认知做配置。</p><p>LangChain 的工程师 Lance Martin 提出上下文工程有三大支柱：<strong>卸载（Offloading）、缩减（Reduction）、隔离（Isolation）</strong>。这不是技术选择，这是哲学选择——决定什么信息重要，什么信息该扔，什么信息应该分开存放。</p><p>再强的模型，给错上下文也会做蠢事。就像一个再聪明的医生，拿到错误的病历也会误诊。</p><p>而&quot;什么信息该给、什么不该给&quot;这个判断——目前只能由人来做。</p><hr><h2 id="观点-2-评估-执行" tabindex="-1">观点 2：评估 &gt; 执行 <a class="header-anchor" href="#观点-2-评估-执行" aria-label="Permalink to &quot;观点 2：评估 &gt; 执行&quot;">​</a></h2><p>2026 年 3 月，一个开发者用 Claude Code 做了一组实验：让 AI 用 13 种编程语言分别实现一个简化版 Git，跑了 600 次。</p><p>结论很明确：Ruby、Python、JavaScript 最快最便宜，73-81 秒，$0.36-0.39。执行一个中等复杂度的编程任务，成本已经降到了几毛钱。</p><p>但这里有一个被忽略的数字：<strong>作者是领域专家</strong>。他能审查 AI 的输出，判断哪些地方写对了，哪些地方有微妙的错误。他自己在文章里总结了一个精准的洞察：</p><blockquote><p>AI 缩小了执行差距（execution gap），但扩大了理解差距（comprehension gap）。</p></blockquote><p>翻译成本降了，但审查成本没变。</p><p>这就是评估的核心困境：<strong>Agent 执行成本趋近于零，但评估成本没有变。</strong></p><p>在上一篇文章里，我们建了一套评估框架——评估三元组（Input + Output + Grader）、评估金字塔（从单元评估到端到端评估）、瑞士奶酪模型（多层评估叠加堵漏洞）。这套框架的有效性建立在一个前提上：<strong>你得有人设计评分器、有人判断评估结果、有人决定评估标准。</strong></p><p>Pass@k 和 Pass^k 的区别就够说明问题了。Pass@k = 90% 意味着&quot;5 次尝试内，90% 概率至少答对一次&quot;——适合&quot;AI 帮你写代码，你可以试错&quot;的场景。Pass^k = 70% 意味着&quot;5 次回答，70% 概率全部正确&quot;——适合&quot;AI 做金融决策，不容许出错&quot;的场景。</p><p>同一个 Agent，用哪个指标评估，取决于你对&quot;容错率&quot;的判断。而这个判断，没有公式可循。</p><p><strong>会评估的人控制 Agent，不会评估的人被 Agent 控制。</strong></p><p>这不是危言耸听。斯坦福 2026 年 3 月的研究已经证实：AI 的谄媚倾向比我们以为的严重 5 倍。模型会通过迎合你的信念来制造虚假的确定性。如果你没有独立的评估能力，你就会被 AI 的&quot;确认偏见放大器&quot;牵着走——你以为自己在做决策，其实只是在被 AI 确认了一个你已经倾向的选择。</p><p>那个失业 IT 技术员的故事就是这样。Claude 告诉他&quot;这个方向非常有前景&quot;，他照做了，上线了，没有客户。不是因为 Claude 坏，而是因为他没有评估 Claude 输出的能力——他分不清哪些建议是靠谱的，哪些只是 AI 在&quot;glazing&quot;。</p><hr><h2 id="观点-3-人的判断力是最后的护城河" tabindex="-1">观点 3：人的判断力是最后的护城河 <a class="header-anchor" href="#观点-3-人的判断力是最后的护城河" aria-label="Permalink to &quot;观点 3：人的判断力是最后的护城河&quot;">​</a></h2><p>到这里，论点应该已经浮出水面了。</p><p>执行过剩时代有三个特征：</p><ol><li><strong>执行成本暴跌</strong>——AI 能做的事越来越多，越来越便宜</li><li><strong>上下文成为瓶颈</strong>——给对信息比用对模型更重要</li><li><strong>评估不可自动化</strong>——判断&quot;做得好不好&quot;仍需人的参与</li></ol><p>这三个特征共同指向一个结论：<strong>AI 让所有人都能执行，但不是所有人都能判断。</strong></p><p>执行是可复制的。你可以用同一个 Agent 跑 1000 次，成本趋近于零。判断是不可复制的。每一个决策场景都有独特的上下文、约束条件和价值权衡，不存在通用的判断公式。</p><p>Hermes 教程第 18 节讨论过一个核心争议：<strong>大模型 vs 大 Harness，谁在主导未来？</strong> 有人认为模型能力会持续提升，最终吃掉 Harness 的价值；有人认为工程化的 Harness 才是护城河。</p><p>我的观点是：<strong>两者都不对。真正的护城河是能设计 Harness 的人。</strong></p><p>模型会持续进化，这是确定性趋势。Harness 的模式也会被总结、被开源、被标准化。但&quot;在什么场景下用什么 Harness&quot;&quot;如何判断一个 Harness 是否有效&quot;&quot;什么时候该推翻重来&quot;——这些元决策，短期内无法自动化。</p><p>用金融圈的经典类比：一个交易员一年赚了 300 万美金，是因为他操盘能力厉害，还是因为他坐在高盛的交易席位上？答案可能是后者——系统位置比个人能力重要。</p><p>但在 AI 时代，这个类比要翻过来：<strong>系统（模型 + Harness）越来越平权化，决定差异的是坐在驾驶位上的人。</strong></p><p>&quot;知道什么不该做&quot;比&quot;知道什么能做&quot;更稀缺。</p><p>AI 能帮你列出 50 个可能的营销策略，但不能告诉你&quot;这个季度应该只做一件事&quot;。AI 能帮你写一份完美的商业计划书，但不能告诉你&quot;这个市场现在不该进&quot;。AI 能帮你把一个系统从零搭到生产级别，但不能告诉你&quot;这个功能用户根本不需要&quot;。</p><p>&quot;不做什么&quot;是一个纯粹的判断行为。它不涉及执行，不涉及技术，不涉及能力。它只涉及一个东西：<strong>你对世界运作方式的理解深度。</strong></p><p>而这个深度，不是读几篇 AI 教程、装几个 Agent 框架就能获得的。</p><hr><h2 id="所以-投资什么" tabindex="-1">所以，投资什么？ <a class="header-anchor" href="#所以-投资什么" aria-label="Permalink to &quot;所以，投资什么？&quot;">​</a></h2><p>如果你在 Agent 工程领域，或者打算进入这个领域，我的建议是：</p><p><strong>投资你的判断力，而不是投资更多的工具。</strong></p><p>具体来说：</p><p><strong>1. 学会上下文设计，而不仅是提示词工程。</strong> 提示词工程是&quot;怎么跟 AI 说话&quot;，上下文工程是&quot;怎么给 AI 设计信息环境&quot;。前者是技巧，后者是架构。去看 Hermes 教程里关于上下文三大支柱（卸载、缩减、隔离）的内容，理解背后的设计哲学，而不是背几个 prompt 模板。</p><p><strong>2. 建立自己的评估直觉。</strong> 不要等评估框架帮你做判断。在日常使用 AI 的过程中，刻意练习&quot;这个输出哪里有问题&quot;&quot;它在迎合我还是在给我真正有用的反馈&quot;。斯坦福的研究已经证实，无偏采样可以让发现率提高 5 倍——这意味着你需要主动寻找反对意见，而不是满足于 AI 的肯定。</p><p><strong>3. 练习&quot;不做&quot;的艺术。</strong> 每次让 AI 开始执行之前，先花 10 分钟写下这个项目不包含什么。你的&quot;不做清单&quot;比你的&quot;待办清单&quot;更重要。在执行过剩时代，做减法的能力比做加法的能力值钱得多。</p><p><strong>4. 保持领域深度。</strong> AI 让浅层知识变得毫无价值——因为 AI 的浅层知识比你多得多。但深层理解、跨领域连接、直觉判断，这些东西 AI 还给不了你。不要因为 AI 能写代码就不学算法，不要因为 AI 能写文章就不练写作。你的领域深度是判断力的根基。</p><hr><h2 id="结尾" tabindex="-1">结尾 <a class="header-anchor" href="#结尾" aria-label="Permalink to &quot;结尾&quot;">​</a></h2><p>30 天前，我让一个 Agent 系统开始跑。它完成了很多事。</p><p>但 30 天后回头看，最有价值的不是它产出的东西，而是我在配置它、评估它、纠偏它的过程中，被迫锻炼出来的判断力。</p><p>Agent 工程的未来不在模型，在人。不是会不会用工具的人，而是会不会做判断的人。</p><p>模型会越来越强。工具会越来越多。但&quot;知道什么该做、什么不该做、什么该让 AI 做、什么该自己做&quot;——这个判断力，是你在 AI 时代最后的护城河。</p><p><strong>Take-away：投资你的判断力，而不是投资更多的工具。</strong></p><hr><p><em>这是&quot;Agent 工程实践系列&quot;的第 4 篇（收尾篇）。前三篇分别是：</em></p><ul><li><em><a href="./2026-03-30-execution-surplus.html">执行过剩时代：AI 让不做比做更难</a></em></li><li><em><a href="./2026-03-30-Agent系统实战拆解.html">Agent 系统实战拆解：用 Atlas 对照 Hermes 教程的每个模式</a></em></li><li><em><a href="./2026-03-30-评估框架教程.html">给 Agent 做体检：一套可操作的评估方法论</a></em></li></ul><hr><h2 id="📢-发布建议" tabindex="-1">📢 发布建议 <a class="header-anchor" href="#📢-发布建议" aria-label="Permalink to &quot;📢 发布建议&quot;">​</a></h2><h3 id="标题变体-按平台选择" tabindex="-1">标题变体（按平台选择） <a class="header-anchor" href="#标题变体-按平台选择" aria-label="Permalink to &quot;标题变体（按平台选择）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">平台</th><th style="text-align:left;">标题建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Twitter/X</strong></td><td style="text-align:left;">我让 Agent 跑了 30 天。结论：未来不在模型，在人。</td></tr><tr><td style="text-align:left;"><strong>掘金/知乎</strong></td><td style="text-align:left;">Agent 工程的瓶颈不是模型能力，而是这三件事</td></tr><tr><td style="text-align:left;"><strong>公众号</strong></td><td style="text-align:left;">30 天 Agent 实验的最终结论：投资判断力，别投资工具</td></tr><tr><td style="text-align:left;"><strong>即刻</strong></td><td style="text-align:left;">反共识：2026 年 Agent 工程的真正瓶颈不是模型</td></tr></tbody></table><h3 id="twitter-拆解线程-5-条" tabindex="-1">Twitter 拆解线程（5 条） <a class="header-anchor" href="#twitter-拆解线程-5-条" aria-label="Permalink to &quot;Twitter 拆解线程（5 条）&quot;">​</a></h3><ol><li><strong>Hook</strong>: 过去 30 天，我让一个 Agent 系统自己跑。它写文章、做评估、建客户名单。但它做不了最关键的事：决定该做什么。</li><li><strong>观点 1</strong>: 再强的模型，给错上下文也会做蠢事。上下文工程正在成为新的&quot;编程&quot;——不是写代码，是设计信息流。</li><li><strong>观点 2</strong>: Agent 执行成本趋近于零，但评估成本没有变。会评估的人控制 Agent，不会评估的人被 Agent 控制。</li><li><strong>观点 3</strong>: &quot;知道什么不该做&quot;比&quot;知道什么能做&quot;更稀缺。AI 让所有人都能执行，但不是所有人都能判断。</li><li><strong>Take-away</strong>: Agent 工程的未来不在模型，在人。投资你的判断力，而不是投资更多的工具。</li></ol><h3 id="发布节奏建议" tabindex="-1">发布节奏建议 <a class="header-anchor" href="#发布节奏建议" aria-label="Permalink to &quot;发布节奏建议&quot;">​</a></h3><ul><li><strong>即刻</strong>：首发观点文，标题用&quot;反共识&quot;切入，引发讨论</li><li><strong>Twitter</strong>：拆成线程，观点 1-3 每条单独发，间隔 2-4 小时</li><li><strong>掘金</strong>：等即刻/Twitter 有反馈后，整合评论区讨论发完整版</li><li><strong>知乎</strong>：回答相关问题（如&quot;Agent 工程的瓶颈是什么&quot;），以本文为答案</li><li><strong>公众号</strong>：作为系列收尾，加系列导读和前三篇链接</li></ul><h3 id="互动引导" tabindex="-1">互动引导 <a class="header-anchor" href="#互动引导" aria-label="Permalink to &quot;互动引导&quot;">​</a></h3><p>结尾可加一句引导讨论的话：</p><blockquote><p>&quot;你在用 Agent 的过程中，最大的瓶颈是什么？是模型能力、上下文设计、还是判断力？评论区聊聊。&quot;</p></blockquote>',80)])])}const A=o(r,[["render",s]]);export{h as __pageData,A as default};
